#!/usr/bin/env bash
# ============================================================================
# Protected Files Guard — v{{VERSION}}
# Event: PreToolUse | Matcher: Edit,Write
# Generated by {{PROJECT_NAME}} harness-marketplace plugin
# Reads JSON from stdin (Claude Code v2 hook format)
# Exit: 0 = allow, 2 = deny (Claude sees stderr)
# ============================================================================
set -euo pipefail

# shellcheck disable=SC1091
source "$(dirname "$0")/_log.sh"
# shellcheck disable=SC1091
source "$(dirname "$0")/_parse.sh"

# ═══ GENERATED RULES (overwritten on upgrade) ═══

FILE_PATH="${TOOL_FILE_PATH:-}"

if [[ -z "$FILE_PATH" ]]; then
  exit 0
fi

# Normalize path separators for cross-platform compatibility
FILE_PATH="${FILE_PATH//\\//}"

# Built-in protected patterns (always enforced)
BUILTIN_PATTERNS=(
  '.env'
  '.env.*'
  '.env.local'
  '.env.production'
  '*.lock'
  'package-lock.json'
  'pnpm-lock.yaml'
  'yarn.lock'
  'bun.lockb'
)

# Project-configured protected patterns
CONFIG_PATTERNS=(
  {{PROTECTED_FILES}}
)

check_pattern() {
  local pattern="$1"
  local filepath="$2"
  local basename
  basename="$(basename "$filepath")"

  # Check against basename using glob matching
  # shellcheck disable=SC2254
  case "$basename" in
    $pattern) return 0 ;;
  esac

  # Check against full path using glob matching
  # shellcheck disable=SC2254
  case "$filepath" in
    *$pattern*) return 0 ;;
  esac

  return 1
}

# Check built-in patterns
for pattern in "${BUILTIN_PATTERNS[@]}"; do
  if check_pattern "$pattern" "$FILE_PATH"; then
    log_block "protected-files" "builtin-pattern" "pattern=$pattern path=$FILE_PATH"
    echo "[PROTECTED] File '$FILE_PATH' matches protected pattern '$pattern'." >&2
    echo "This file should not be modified by automated tools." >&2
    echo "If you must edit this file, do so manually and review carefully." >&2
    exit 2
  fi
done

# Check project-configured patterns
for pattern in "${CONFIG_PATTERNS[@]}"; do
  [[ -z "$pattern" ]] && continue
  if check_pattern "$pattern" "$FILE_PATH"; then
    log_block "protected-files" "config-pattern" "pattern=$pattern path=$FILE_PATH"
    echo "[PROTECTED] File '$FILE_PATH' matches protected pattern '$pattern'." >&2
    echo "This file is protected by project configuration." >&2
    exit 2
  fi
done

# ═══ CUSTOM RULES BELOW (preserved on upgrade) ═══

# Add your own protected file patterns here.
# They will be preserved when the plugin is upgraded.
#
# Example:
#   case "$(basename "$FILE_PATH")" in
#     'my-critical-config.yaml')
#       log_block "protected-files" "custom-rule" "path=$FILE_PATH"
#       echo "[PROTECTED] Custom rule: my-critical-config.yaml is protected" >&2
#       exit 2
#       ;;
#   esac

exit 0
